    function sentupdate()
    {
        var stringArray = new Array();
        stringArray[0] = document.getElementById(""txtTempLow"").value;
        stringArray[1] = document.getElementById(""txtTempHigh"").value;
        stringArray[2] = document.getElementById(""txtInterval"").value;
        stringArray[3] = document.getElementById(""txtPWMlow"").value;
        stringArray[4] = document.getElementById(""txtPWMHigh"").value;
        
        if (stringArray[0] == null || stringArray[0] == """")
        {
            $.bsAlert.alert(""Please fill temp at low speed."");
            return false;
        }

        if (stringArray[0] < 0 || stringArray[0] > 100)
        {
